# Python 3.11+
"""Two SEAMS: the discount MATH (Strategy) and the eligibility CONDITIONS (a
chain of rules).

  - DiscountStrategy.compute(cart, coupon) -> int cents : HOW MUCH to take off.
    Three concretes; all integer-cents, all clamped so a discount never exceeds
    the cart subtotal.
  - EligibilityRule.check(cart, coupon, now) -> None | raises : WHETHER the coupon
    applies. Composed into an ordered chain where EVERY rule must pass; the first
    failure raises its specific typed error (the failure reason).
"""

from abc import ABC, abstractmethod

from models import (
    Cart,
    Coupon,
    CouponExpiredError,
    DiscountType,
    IneligibleCartError,
    InvalidCouponError,
)


# ── discount math (Strategy) ─────────────────────────────────────────────────────
class DiscountStrategy(ABC):
    @abstractmethod
    def compute(self, cart: Cart, coupon: Coupon) -> int:
        """Discount in integer cents, never more than the cart subtotal."""


class PercentageDiscount(DiscountStrategy):
    def compute(self, cart: Cart, coupon: Coupon) -> int:
        subtotal = cart.subtotal_cents
        raw = subtotal * coupon.percent // 100          # integer cents, floor
        if coupon.max_discount_cents > 0:
            raw = min(raw, coupon.max_discount_cents)    # honour the cap
        return min(raw, subtotal)


class FlatDiscount(DiscountStrategy):
    def compute(self, cart: Cart, coupon: Coupon) -> int:
        return min(coupon.flat_cents, cart.subtotal_cents)   # never below zero total


class BuyXGetYDiscount(DiscountStrategy):
    """For every (buy_x + get_y) eligible units, the cheapest get_y are free."""

    def compute(self, cart: Cart, coupon: Coupon) -> int:
        if coupon.buy_x <= 0 or coupon.get_y <= 0:
            raise InvalidCouponError("buy_x and get_y must be positive")
        # Expand units, cheapest first; the cheapest get_y of each full group are free.
        unit_prices: list[int] = []
        for item in cart.items:
            unit_prices.extend([item.price_cents] * item.quantity)
        unit_prices.sort()                              # cheapest first
        group = coupon.buy_x + coupon.get_y
        free_count = (len(unit_prices) // group) * coupon.get_y
        discount = sum(unit_prices[:free_count])        # the cheapest `free_count` units
        return min(discount, cart.subtotal_cents)


_DISCOUNTS: dict[DiscountType, DiscountStrategy] = {
    DiscountType.PERCENTAGE: PercentageDiscount(),
    DiscountType.FLAT: FlatDiscount(),
    DiscountType.BUY_X_GET_Y: BuyXGetYDiscount(),
}


def make_discount_strategy(discount_type: DiscountType) -> DiscountStrategy:
    """Factory: map the coupon's DiscountType to the right math."""
    try:
        return _DISCOUNTS[discount_type]
    except KeyError as exc:
        raise InvalidCouponError(f"unsupported discount type {discount_type}") from exc


# ── eligibility (Chain of rules) ─────────────────────────────────────────────────
class EligibilityRule(ABC):
    @abstractmethod
    def check(self, cart: Cart, coupon: Coupon, now: int) -> None:
        """Raise a specific CouponError if this rule fails; return None if it passes."""


class ValidityWindowRule(EligibilityRule):
    def check(self, cart: Cart, coupon: Coupon, now: int) -> None:
        if not (coupon.valid_from <= now <= coupon.valid_until):
            raise CouponExpiredError(f"coupon {coupon.code} is not valid at {now}")


class MinCartValueRule(EligibilityRule):
    def check(self, cart: Cart, coupon: Coupon, now: int) -> None:
        if cart.subtotal_cents < coupon.min_cart_cents:
            raise IneligibleCartError(
                f"cart {cart.subtotal_cents} below minimum {coupon.min_cart_cents}"
            )


class CategoryRule(EligibilityRule):
    def check(self, cart: Cart, coupon: Coupon, now: int) -> None:
        if coupon.allowed_categories and not (cart.categories() & coupon.allowed_categories):
            raise IneligibleCartError(
                f"cart has no items in {set(coupon.allowed_categories)}"
            )


class FirstOrderRule(EligibilityRule):
    def check(self, cart: Cart, coupon: Coupon, now: int) -> None:
        if coupon.first_order_only and not cart.is_first_order:
            raise IneligibleCartError("coupon is for first orders only")


# The default chain: cheap checks first, so we fail fast before heavier ones.
DEFAULT_RULES: tuple[EligibilityRule, ...] = (
    ValidityWindowRule(),
    MinCartValueRule(),
    CategoryRule(),
    FirstOrderRule(),
)
